  "questionProse": [
    "किसी ऑब्जेक्ट की सभी Symbol keys प्राप्त करने के लिए किस मेथड का उपयोग किया जाएगा?"
  ],
  "explanationProse": [
    "`Object.getOwnPropertySymbols()` मेथड का उपयोग ऑब्जेक्ट की अपनी Symbol प्रॉपर्टी keys को प्राप्त करने के लिए किया जाता है। चूंकि `Object.keys()` या `for...in` जैसे स्टैंडर्ड इटरेटर्स Symbol keys को इग्नोर कर देते हैं, इसलिए आपको इन्हें एक्सप्लिसिटली फेच करने के लिए इसी मेथड की ज़रूरत पड़ती है।"
  ]
}
